function main({data1}) {
    const questions = [];

    // 按题目编号分割字符串
    const questionBlocks = data1.split(/\n(?=\d+\.)/);

    questionBlocks.forEach(block => {
        const trimmedBlock = block.trim();
        if (!trimmedBlock) return;

        // 查找解析部分的位置
        const analysisIndex = trimmedBlock.indexOf('解析：');

        if (analysisIndex === -1) return;

        // 提取题干部分（从题目开始到解析之前）
        const questionPart = trimmedBlock.substring(0, analysisIndex).trim();

        // 提取解析部分（保留"解析："）
        const analysisPart = trimmedBlock.substring(analysisIndex).trim();

        // 提取填空题的正确答案
        // 匹配模式：正确答案[为是] + 可能的空格 + 答案内容（到句号为止）
        // 支持单个答案或多个答案（用顿号、分隔）
        const answerMatch = analysisPart.match(/正确答案[为是]\s*([^。]+)。/);
        let correctAnswer = '';

        if (answerMatch) {
            // 提取答案文本并清理首尾空格
            correctAnswer = answerMatch[1].trim();

            // 如果答案中包含顿号，说明是多个答案，可以选择保持原样或转换为数组
            // 这里保持原样，如需数组格式可以用 correctAnswer.split('、')
        }

        questions.push({
            Question: questionPart,
            Answer: analysisPart,
            CorrectOption: correctAnswer
        });
    });

    return {
        questions: questions
    };
}

