function main({
    judgmentScore,
    judgmentCount,
    singleChoiceScore,
    singleChoiceCount,
    multipleChoiceScore,
    multipleChoiceCount,
    fillBlankScore,
    fillBlankCount,
    shortAnswerScore,
    shortAnswerCount
}) {
    // 计算各题型总分
    const judgmentTotal = judgmentScore * judgmentCount;
    const singleChoiceTotal = singleChoiceScore * singleChoiceCount;
    const multipleChoiceTotal = multipleChoiceScore * multipleChoiceCount;
    const fillBlankTotal = fillBlankScore * fillBlankCount;
    const shortAnswerTotal = shortAnswerScore * shortAnswerCount;

    // 计算总计分数
    const grandTotal = judgmentTotal + singleChoiceTotal + multipleChoiceTotal + fillBlankTotal + shortAnswerTotal;

    return {
        judgmentTotal,
        singleChoiceTotal,
        multipleChoiceTotal,
        fillBlankTotal,
        shortAnswerTotal,
        grandTotal
    };
}

function main({judgmentCount, singleChoiceCount, multipleChoiceCount, fillBlankCount, shortAnswerCount}) {
    const chineseNumbers = ['一', '二', '三', '四', '五'];
    const counts = [judgmentCount, singleChoiceCount, multipleChoiceCount, fillBlankCount, shortAnswerCount];

    let currentIndex = 0;
    const results = counts.map(count => {
        if (count === 0) {
            return '';
        }
        return chineseNumbers[currentIndex++];
    });

    return {
        judgmentNumber: results[0],
        singleChoiceNumber: results[1],
        multipleChoiceNumber: results[2],
        fillBlankNumber: results[3],
        shortAnswerNumber: results[4]
    };
}
